CREATE TABLE IF NOT EXISTS superstars (internal_id BIGINT PRIMARY KEY, project INT NOT NULL, author VARCHAR(50) NOT NULL, created_at TIMESTAMP NOT NULL, "views" INT NOT NULL, reposts INT NOT NULL, first_seen TIMESTAMP NOT NULL, last_seen TIMESTAMP NULL, last_seen_iteration INT NULL, CONSTRAINT fk_superstars_project__id FOREIGN KEY (project) REFERENCES projects(id) ON DELETE RESTRICT ON UPDATE RESTRICT, CONSTRAINT fk_superstars_author__name FOREIGN KEY (author) REFERENCES users("name") ON DELETE RESTRICT ON UPDATE RESTRICT, CONSTRAINT fk_superstars_last_seen_iteration__id FOREIGN KEY (last_seen_iteration) REFERENCES request_iterations(id) ON DELETE RESTRICT ON UPDATE RESTRICT);